import jwt
import datetime
from typing import Dict, Any, Optional

SECRET_KEY = "your-secret-key-change-this-in-production"
ALGORITHM = "HS256"
TOKEN_EXPIRATION_HOURS = 24


def generate_jwt_token(user_id: int, role: str, additional_claims: Optional[Dict[str, Any]] = None) -> str:
    payload = {
        "user_id": user_id,
        "role": role,
        "iat": datetime.datetime.utcnow(),
        "exp": datetime.datetime.utcnow() + datetime.timedelta(hours=TOKEN_EXPIRATION_HOURS)
    }
    
    if additional_claims:
        payload.update(additional_claims)
    
    token = jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)
    return token


def decode_jwt_token(token: str) -> Dict[str, Any]:
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        return payload
    except jwt.ExpiredSignatureError:
        raise ValueError("Token has expired")
    except jwt.InvalidTokenError:
        raise ValueError("Invalid token")


def verify_token(token: str) -> bool:
    try:
        decode_jwt_token(token)
        return True
    except ValueError:
        return False


def get_user_from_token(token: str) -> Dict[str, Any]:
    payload = decode_jwt_token(token)
    return {
        "user_id": payload.get("user_id"),
        "role": payload.get("role")
    }


if __name__ == "__main__":
    user_id = 12345
    role = "admin"
    
    token = generate_jwt_token(user_id, role)
    print(f"Generated Token: {token}")
    
    decoded = decode_jwt_token(token)
    print(f"Decoded Payload: {decoded}")
    
    is_valid = verify_token(token)
    print(f"Token Valid: {is_valid}")
    
    user_info = get_user_from_token(token)
    print(f"User Info: {user_info}")